mapper.select:
select distinct fr.id, fr.tenant_id, fr.file_code, fr.biz_type, fr.file_category, fr.file_name, fr.file_format_type, fr.file_size_bytes, fr.checksum_type, fr.checksum_value, fr.storage_type, fr.storage_bucket, fr.storage_path, fr.file_status, fr.biz_date, fr.trace_id, fr.metadata_json, fr.created_at, fr.updated_at from batch.file_record fr where fr.tenant_id = #{tenantId} and ( fr.id in ( select ji.related_file_id from batch.job_instance ji where ji.tenant_id = #{tenantId} and ji.id = #{jobInstanceId} and ji.related_file_id is not null ) or fr.id in ( select pi.file_id from batch.pipeline_instance pi where pi.tenant_id = #{tenantId} and pi.related_job_instance_id = #{jobInstanceId} and pi.file_id is not null )
or fr.id = #{payloadFileId}
) order by fr.id asc

select distinct fdr.id, fdr.tenant_id, fdr.file_id, fdr.pipeline_instance_id, fdr.channel_code, fdr.dispatch_target, fdr.dispatch_status, fdr.dispatch_attempt, fdr.receipt_code, fdr.receipt_status, fdr.external_request_id, fdr.error_code, fdr.error_message, fdr.dispatched_at, fdr.ack_at, fdr.created_at, fdr.updated_at from batch.file_dispatch_record fdr left join batch.pipeline_instance pi on pi.tenant_id = fdr.tenant_id and pi.id = fdr.pipeline_instance_id where fdr.tenant_id = #{tenantId} and ( pi.related_job_instance_id = #{jobInstanceId}
or fdr.file_id in
#{fileId}
) order by fdr.id desc limit 100

select distinct fdr.id, fdr.tenant_id, fdr.file_id, fdr.pipeline_instance_id, fdr.channel_code, fdr.dispatch_target, fdr.dispatch_status, fdr.dispatch_attempt, fdr.receipt_code, fdr.receipt_status, fdr.external_request_id, fdr.error_code, fdr.error_message, fdr.dispatched_at, fdr.ack_at, fdr.created_at, fdr.updated_at from archive.file_dispatch_record_archive fdr left join archive.pipeline_instance_archive pi on pi.tenant_id = fdr.tenant_id and pi.id = fdr.pipeline_instance_id where fdr.tenant_id = #{tenantId} and ( pi.related_job_instance_id = #{jobInstanceId}
or fdr.file_id in
#{fileId}
) order by fdr.id desc limit 100
